// CODE_Normalize_Flow3_Input (Webhook + Telegram Trigger compatible)

const root = $json || {};
const body = root.body || null;

// Helpers
const toBool = (v) => v === true || v === "true" || v === 1 || v === "1";

// Normaliza texto para comparar keywords
const normText = (s) =>
  String(s || "")
    .trim()
    .toLowerCase()
    .replace(/[¡!¿?.,;:()[\]{}"“”'’]/g, " ")
    .replace(/\s+/g, " ")
    .trim();

// Detecta keyword de cierre por texto
const isDoneFromText = (text) => {
  const n = normText(text);
  if (!n) return false;

  // Puedes ajustar esta lista si quieres más keywords
  const doneWords = [
    "listo",
    "done",
    "finalizar",
    "terminar",
    "cerrar",
    "finish",
    "completed"
  ];

  // Frases comunes
  const donePhrases = [
    "ok listo",
    "ya listo",
    "estoy listo",
    "todo listo",
    "listo ya",
    "listo gracias",
    "ya termine",
    "ya terminé",
    "terminado",
    "finalizado",
    "ya finalize",
    "ya finalicé"
  ];

  if (doneWords.includes(n)) return true;
  if (donePhrases.includes(n)) return true;

  // Si viene dentro de una oración: "ok, listo. gracias"
  // (evita falsos positivos raros)
  const tokens = n.split(" ");
  if (tokens.includes("listo")) return true;
  if (tokens.includes("done")) return true;

  return false;
};

// 1) Detectar Webhook (Flow1 -> Trigger_Flow3) (normalmente viene en body)
const candidateWebhook = body && (body.chat_id || body.event || body.mode || body.extras_limit !== undefined);

// 2) Detectar Telegram Trigger (message / edited_message)
const t = root.message || root.edited_message || root;

// -------------------------
// A) ENTRADA DESDE WEBHOOK
// -------------------------
if (candidateWebhook) {
  const p = body;

  const text = String(p.text || "").trim();
  const is_done_keyword =
    toBool(p.is_done_keyword) || isDoneFromText(text); // <-- mejora: por si te mandan "listo" desde webhook

  return [{
    chat_id: p.chat_id ? String(p.chat_id) : null,
    telegram_user_id: p.telegram_user_id ? String(p.telegram_user_id) : null,
    username: p.username || "",
    text,
    hasVoice: toBool(p.hasVoice),
    voice_file_id: p.voice_file_id ? String(p.voice_file_id) : null,
    message_id: p.message_id ? String(p.message_id) : null,
    is_done_keyword,
    lang: String(p.lang || "ES").trim().toUpperCase(),
    event: p.event ? String(p.event) : null,     // "open_window"
    mode: p.mode ?? "auto",
    extras_limit: Number.isFinite(p.extras_limit) ? p.extras_limit : parseInt(p.extras_limit ?? 15, 10),
    send_internal_email: !!p.send_internal_email,
    force_refresh: !!p.force_refresh,
    internal_notes: String(p.internal_notes || ""),
    source: p.source || "flow1_webhook",
    raw: root
  }];
}

// -------------------------
// B) ENTRADA DESDE TELEGRAM
// -------------------------
const u = t;

const chat_id =
  (u?.chat?.id != null ? String(u.chat.id) : null) ||
  (u?.chat_id != null ? String(u.chat_id) : null) ||
  null;

const telegram_user_id =
  (u?.from?.id != null ? String(u.from.id) : null) ||
  null;

const username =
  u?.from?.username ||
  [u?.from?.first_name, u?.from?.last_name].filter(Boolean).join(" ").trim() ||
  "";

const message_id =
  (u?.message_id != null ? String(u.message_id) : null) ||
  null;

const text = String(u?.text || u?.caption || "").trim();

let hasVoice = !!u?.voice;
let voice_file_id = u?.voice?.file_id || null;

// compat: audio
if (!hasVoice && u?.audio?.file_id) {
  hasVoice = true;
  voice_file_id = u.audio.file_id;
}

// ✅ mejora clave: detectar "listo" aquí mismo
const is_done_keyword = isDoneFromText(text);

return [{
  chat_id,
  telegram_user_id,
  username,
  text,
  hasVoice,
  voice_file_id: voice_file_id ? String(voice_file_id) : null,
  message_id,
  is_done_keyword,                 // <-- ahora sí viene true cuando escriben "listo"
  lang: "ES",                      // opcional: puedes mapear desde Sheet luego
  event: null,
  mode: null,
  extras_limit: null,
  send_internal_email: null,
  force_refresh: null,
  internal_notes: "",
  source: "telegram",
  raw: root
}];

