  (() => {
    const row = $node["GS_Lead_Lookup"].json;

    const opened = String(row.flow3_opened_at || '').trim();
    const expires = String(row.flow3_expires_at || '').trim();
    const closed = String(row.flow3_closed_at || '').trim();

    if (!opened || !expires) return false;   // nunca se abrió ventana
