const input = $node["CODE_Normalize_Flow3_Input"].json;
const lead = $node["GS_Lead_Lookup"].json;

const nowIso = new Date().toISOString();

function safeStr(v) {
  if (v === null || v === undefined) return "";
  return String(v).trim();
}

function compactText(str, maxLen = 500) {
  const s = safeStr(str).replace(/\s+/g, " ");
  return s.length > maxLen ? s.slice(0, maxLen) + "…" : s;
}

// 1) transcript SOLO si hay voz
let transcript = "";
if (input.hasVoice) {
  const ai = $node["AI_Transcribe_Voice"].json || {};
  transcript = safeStr(ai.text || ai.transcript || "");
}

// 2) content final: voz -> transcript / texto -> input.text
const content = input.hasVoice
  ? transcript
  : safeStr(input.text);

// 3) safety: si no hay contenido útil
if (!content) {
  return [{
    chat_id: safeStr(input.chat_id),
    extra_id: `F3-${safeStr(lead.flow3_request_id || input.chat_id)}-${safeStr(input.message_id || Math.random().toString(36).slice(2, 8))}`,
    source: "flow3",
    from: input.hasVoice ? "voice" : "text",
    received_at: nowIso,
    content_type: input.hasVoice ? "transcript" : "text",
    content: "",
    raw: JSON.stringify(input),
    raw_compact: "",
    tags: "flow3_empty"
  }];
}

// 4) extra_id estable
const extra_id = `F3-${safeStr(lead.flow3_request_id || input.chat_id)}-${safeStr(input.message_id || Math.random().toString(36).slice(2, 8))}`;

// 5) raw estructurado
const rawPayload = input.hasVoice
  ? {
      input,
      transcript
    }
  : input;

// 6) raw compact para lectura rápida
const raw_compact = compactText(content, 300);

return [{
  chat_id: safeStr(input.chat_id),
  extra_id,
  source: "flow3",
  from: input.hasVoice ? "voice" : "text",
  received_at: nowIso,
  content_type: input.hasVoice ? "transcript" : "text",
  content,
  raw: JSON.stringify(rawPayload),
  raw_compact,
  tags: "flow3"
}];

